sql:
SELECT bus_number
FROM buses
WHERE bus_id IN (
  SELECT bus_id
  FROM bus_assignments
);

SELECT route_id, COUNT(bus_stop_id) AS BusStopsCount
FROM bus_stop_routes
GROUP BY route_id;

SELECT location
FROM bus_stops
WHERE y = (SELECT MAX(y) FROM bus_stops);

SELECT COUNT(*)
FROM bus_assignments
WHERE bus_id = 0;

SELECT first_name, last_name, hire_date 
FROM drivers 
WHERE driver_id = 1;

SELECT bus_stop_type, description
FROM bus_stop_types
WHERE is_terminal = 1;
